### Description

BatchedMesh needs a good cleanup method.  After inspecting its code I'm fairly sure it's not possible to do a cleanup using only getGeometryIdAt / deleteGeometry / optimize methods.  

The optimize method is supposed to free up unused space and shift _nextVertexStart and _nextIndexStart values, but there is a corner case when all geometries are deleted, mentioned variables are not reset to zero.

As a result it won't add new geometries at some point throwing an error 'THREE.BatchedMesh: Reserved space request exceeds the maximum buffer size.'

To workaround this issue I can set these variables to zero, but they are supposed to be private. Or never have all geometries removed before calling optimize.

### Reproduction steps

1. Initialize BatchedMesh with some limits on vertex, index and instance count.
2. Fill the batch with one or more geometries. Then clear it and call optimize.
3. Repeat a number of times until error is thrown.


### Code

```js
import * as THREE from 'three';
import { BatchedMesh } from 'three';

let renderer, scene, camera;

init();

function init() {

    // renderer
    renderer = new THREE.WebGLRenderer();
    renderer.setSize( window.innerWidth, window.innerHeight );
    renderer.setPixelRatio( window.devicePixelRatio );
    renderer.setAnimationLoop( animate );
    document.body.appendChild( renderer.domElement );

    // scene
    scene = new THREE.Scene();

    // geometry
    const geometry = new THREE.SphereGeometry( 5, 12, 8 );

    // material
    const material = new THREE.MeshPhongMaterial( {
        color: 0x00ffff, 
        flatShading: true,
        transparent: true,
        opacity: 0.7,
    } );

    const MAX_INSTANCES = 128;
    const MAX_VERTEX = 512;
    const MAX_INDEX = 512 * 4;
    const batch = new BatchedMesh(MAX_INSTANCES, MAX_VERTEX, MAX_INDEX, material);

    const clearBatch = () => {
        for (let i = batch.instanceCount - 1; i >= 0; --i) {
            const geomId = batch.getGeometryIdAt(i);
            batch.deleteGeometry(geomId);
        }
        batch.optimize();

        // TODO bug in threejs BatchedMesh: if I remove all geometries, the internal variables of BatchedMesh nextIndexStart and nextVertexStart do not change
        // const bugfix = batch;
        // bugfix._nextIndexStart = 0
        // bugfix._nextVertexStart = 0
    }

    const fillBatch = () => {
        for (let i = 0; i < 2; ++i) {
            const geometryId = batch.addGeometry(geometry);
            batch.addInstance(geometryId);
        }
    }

    // cycle until batched mesh complains
    for (let i = 0; i<128; ++i) {
        clearBatch();
        try {
            fillBatch();
        } catch (e) {
            console.error('Attempt ', i);
            throw e;
        }
    }
}

function animate() {
    // renderer.render( scene, camera );
}
```


