### Description

When attempting to render two scenes that use `viewportLinearDepth` to two different targets I noticed that only one scene would render with correct depth.

Further investigation led me to ViewportDepthTextureNode and it's singleton `_sharedDepthbuffer` that will be re-used for all nodes regardless of their render target.

`ViewportTextureNode` appears to handle buffer referencing per render target using a weak map but `ViewportDepthTextureNode` overrides its `getTextureForReference()` to return the singleton instead.

There is also `ViewportSharedTextureNode` that does the same trick but its only used by `Line2NodeMaterial`

I haven't tested this with multiple contexts but I imagine that sharing buffers across contexts would break as well.

### Reproduction steps

1. Render two scenes to two different render targets and use `viewportLinearDepth` for example
2. Notice that only one is rendering correctly

See jsfiddle for example

### Code

```js
import * as THREE from 'three/webgpu';
			import { linearDepth, viewportLinearDepth, vec3 } from 'three/tsl';

			import WebGPU from 'three/addons/capabilities/WebGPU.js';

			if ( WebGPU.isAvailable() === false ) {

				document.body.appendChild( WebGPU.getErrorMessage() );
				throw new Error( 'No WebGPU support' );

			}

			let renderer;
			const views = [];

			init();

			function createView( canvasId, rotationSpeed, width, height ) {

				const canvas = document.getElementById( canvasId );
				const canvasTarget = new THREE.CanvasTarget( canvas );
				canvasTarget.setPixelRatio( window.devicePixelRatio );
				canvasTarget.setSize( width, height );

				const scene = new THREE.Scene();

				const camera = new THREE.PerspectiveCamera( 50, 1, 0.1, 10 );
				camera.position.set( 0, 4, 0 );
				camera.lookAt( 0, 0, 0 );

				const depthDistance = viewportLinearDepth.distance( linearDepth() );

				const cube = new THREE.Mesh(
          new THREE.SphereGeometry( 0.75, 32, 32 ),
          new THREE.MeshBasicNodeMaterial( {
            colorNode: vec3( depthDistance ),
            side: THREE.DoubleSide
          } )
        );
				cube.renderOrder = 1;
				scene.add( cube );

        const bgKnot = new THREE.Mesh(
          new THREE.TorusKnotGeometry( 1, 0.4, 50, 20 ),
          new THREE.MeshBasicNodeMaterial()
        );
        bgKnot.rotation.x = - Math.PI / 2;
        bgKnot.position.y = - 2.8;
        scene.add( bgKnot );

				return {
					canvasTarget,
					scene,
					camera,
					cube,
					rotationSpeed,
          bgKnot,
				};

			}

			function init() {

				renderer = new THREE.WebGPURenderer( { antialias: true } );
				renderer.setPixelRatio( window.devicePixelRatio );
				renderer.setAnimationLoop( animate );

				views.push( createView( 'canvas1', 0.2, 360, 360 ) );
				views.push( createView( 'canvas2', 0.8, 360, 360 ) );

			}

			function animate() {

				const time = performance.now() * 0.001;

				for ( const view of views ) {

					view.cube.rotation.x = time * view.rotationSpeed;
					view.cube.rotation.y = time * view.rotationSpeed * 0.7;
					view.bgKnot.rotation.x = time * view.rotationSpeed;
					view.bgKnot.rotation.y = time * view.rotationSpeed * 0.7;

					renderer.setCanvasTarget( view.canvasTarget );
					renderer.render( view.scene, view.camera );

        }

      }
